// Läuft im n8n-runners-Sidecar. 'fs'/'path' sind dort per
// NODE_FUNCTION_ALLOW_BUILTIN freigegeben (compose/compose.app.yaml).
// Das Ziel /data/agent-workspace ist das gemeinsame, einzige beschreibbare
// persistente Verzeichnis (n8n-agent-workspace-Volume).
const fs = require('fs');
const path = require('path');
const WORKSPACE = '/data/agent-workspace';

let input = query;
if (typeof input === 'string') {
  try { input = JSON.parse(input); } catch (e) {
    return 'FEHLER: Eingabe muss ein JSON-Objekt mit {"dateiname", "inhalt"} sein.';
  }
}
const name = String((input && input.dateiname) || '').trim();
const inhalt = String((input && input.inhalt) != null ? input.inhalt : '');
if (!name) return 'FEHLER: dateiname fehlt.';

// Path-Traversal verhindern: nur nackter Dateiname, konservativer Zeichensatz.
const safe = path.basename(name).replace(/[^A-Za-z0-9._\-]/g, '_');
if (!safe || safe === '.' || safe === '..') return 'FEHLER: ungültiger Dateiname.';
const target = path.join(WORKSPACE, safe);

fs.writeFileSync(target, inhalt, 'utf8');
return 'Gespeichert: ' + target + ' (' + Buffer.byteLength(inhalt, 'utf8') + ' Bytes)';
